import{_ as r,o as t,c as e,a2 as o}from"./chunks/framework.BWuWLRhz.js";const l="/assets/v2rayng-02.6OOqgDGC.png",p=JSON.parse('{"title":"v2rayNG for Android","description":"Android 备选客户端 v2rayNG 教程，支持一键导入与手动导入两种方式。","frontmatter":{"description":"Android 备选客户端 v2rayNG 教程，支持一键导入与手动导入两种方式。"},"headers":[],"relativePath":"clients/android/v2rayng.md","filePath":"clients/android/v2rayng.md","lastUpdated":1783294793000}'),i={name:"clients/android/v2rayng.md"};function d(n,a,s,h,u,c){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="v2rayng-for-android" tabindex="-1">v2rayNG for Android <a class="header-anchor" href="#v2rayng-for-android" aria-label="Permalink to &quot;v2rayNG for Android&quot;">​</a></h1><blockquote><p><strong>Android 轻量客户端</strong> | 导入订阅快、连接直观、兼容性高。Android 首选推荐见 <a href="./clash-meta">Clash Meta</a>。</p></blockquote><p><a href="https://github.com/2dust/v2rayNG" target="_blank" rel="noreferrer">v2rayNG</a> 是 Android 平台常用的代理客户端，适合希望快速完成订阅导入并直接连接节点的用户。</p><h2 id="支持协议" tabindex="-1">支持协议 <a class="header-anchor" href="#支持协议" aria-label="Permalink to &quot;支持协议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>协议</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>VMess</td><td>支持</td><td>常见 V2Ray 协议</td></tr><tr><td>VLESS</td><td>支持</td><td>新版主流协议</td></tr><tr><td>Trojan</td><td>支持</td><td>伪装流量方案</td></tr><tr><td>Shadowsocks</td><td>支持</td><td>兼容旧节点</td></tr><tr><td>SOCKS</td><td>支持</td><td>通用代理支持</td></tr></tbody></table><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li>操作系统：Android 8.0 及以上</li><li>权限需求：网络权限、VPN 权限</li><li>存储空间：100MB 可用空间</li></ul><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>Android universal（直链）：<a href="https://github.com/2dust/v2rayNG/releases/download/2.0.15/v2rayNG_2.0.15_universal.apk" target="_blank" rel="noreferrer">下载 APK</a></li><li>Android universal（镜像加速）：<a href="https://gh.xxooo.cf/https://github.com/2dust/v2rayNG/releases/download/2.0.15/v2rayNG_2.0.15_universal.apk" target="_blank" rel="noreferrer">下载 APK</a></li><li>当前参考版本：<code>2.0.15</code></li></ul><p>安装步骤：下载 universal.apk 后安装，启动应用并允许 VPN 权限。</p><h2 id="导入订阅" tabindex="-1">导入订阅 <a class="header-anchor" href="#导入订阅" aria-label="Permalink to &quot;导入订阅&quot;">​</a></h2><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，有两种方式导入到 v2rayNG：</p><p><img src="'+l+'" alt="会员中心复制订阅链接或一键导入 v2rayNG"></p><h3 id="方式一-一键导入-推荐" tabindex="-1">方式一：一键导入（推荐） <a class="header-anchor" href="#方式一-一键导入-推荐" aria-label="Permalink to &quot;方式一：一键导入（推荐）&quot;">​</a></h3><p>在手机浏览器打开会员中心，点击 <strong>V2rayNg</strong> 图标下方的<strong>导入</strong>按钮，系统会自动唤起 v2rayNG 并添加订阅，无需手动复制粘贴。</p><h3 id="方式二-手动导入" tabindex="-1">方式二：手动导入 <a class="header-anchor" href="#方式二-手动导入" aria-label="Permalink to &quot;方式二：手动导入&quot;">​</a></h3><ol><li>点击订阅链接右侧的<strong>复制</strong>按钮，复制订阅链接</li><li>打开 v2rayNG，点击右上角的<strong>加号（+）</strong></li><li>选择<strong>从剪贴板导入</strong>（Import config from Clipboard）</li><li>导入成功后，点击右上角的<strong>更新</strong>图标拉取节点</li></ol><h2 id="连接节点" tabindex="-1">连接节点 <a class="header-anchor" href="#连接节点" aria-label="Permalink to &quot;连接节点&quot;">​</a></h2><ol><li>在订阅组中长按并选择<strong>更新订阅</strong>，确保节点列表为最新</li><li>点选一个延迟较低的节点</li><li>点击右下角的连接按钮，首次连接时允许系统的 VPN 请求</li><li>打开浏览器访问外网，验证是否连接正常</li></ol><h2 id="进阶说明" tabindex="-1">进阶说明 <a class="header-anchor" href="#进阶说明" aria-label="Permalink to &quot;进阶说明&quot;">​</a></h2><ul><li><strong>路由设置</strong>：可按需设置全局代理或分流模式，也可配置绕过局域网地址</li><li><strong>流量统计</strong>：实时查看上行 / 下行速度，观察连接稳定性和节点表现</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 导入报错或订阅为空？</strong> A: 链接可能失效或不完整；先在浏览器测试链接是否有返回，再重新导入。</p><p><strong>Q: 连上后打不开网页？</strong> A: 切换节点重试，检查 VPN 权限是否仍在，确认本地时间准确。</p><p><strong>Q: 节点全部超时？</strong> A: 先切换网络（Wi-Fi / 蜂窝），再更新订阅；如仍异常，见<a href="./../../guide/faq">常见问题 FAQ</a>。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li>项目主页：<a href="https://github.com/2dust/v2rayNG" target="_blank" rel="noreferrer">https://github.com/2dust/v2rayNG</a></li><li>问题反馈：<a href="https://github.com/2dust/v2rayNG/issues" target="_blank" rel="noreferrer">https://github.com/2dust/v2rayNG/issues</a></li></ul><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用版本 v2rayNG 2.0.15</p></blockquote>',29)])])}const b=r(i,[["render",d]]);export{p as __pageData,b as default};
